fsm.machine @mbx_fsm(
  // Inputs from Verilog module
  %mbx_range_valid_i: i1,
  %hostif_abort_ack_i: i1,
  %mbx_error_set_i: i1,
  %sysif_control_abort_set_i: i1,
  %sys_read_all_i: i1,
  %writer_close_mbx_i: i1,
  %writer_last_word_written_i: i1,
  %writer_write_valid_i: i1
